Add-Type -AssemblyName 'System.Drawing'
Add-Type -TypeDefinition @'
using System;
using System.Drawing;
using System.Drawing.Imaging;
using System.Runtime.InteropServices;

[StructLayout\(LayoutKind.Sequential\)]
public struct SIZE2 { public int cx; public int cy; }

[Flags]
public enum SIIGBF2 { ResizeToFit = 0 }

[ComImport, Guid\(\\"bcc18b79-ba16-442f-80c4-8a59c30c463b\\"\), InterfaceType\(ComInterfaceType.InterfaceIsIUnknown\)]
public interface IShellItemImageFactory2 {
    [PreserveSig]
    int GetImage\([In, MarshalAs\(UnmanagedType.Struct\)] SIZE2 size, [In] SIIGBF2 flags, [Out] out IntPtr phbm\);
}

public class ThumbExtract {
    [DllImport\(\\"shell32.dll\\", CharSet = CharSet.Unicode, PreserveSig = false\)]
    public static extern void SHCreateItemFromParsingName\(string pszPath, IntPtr pbc, [In] ref Guid riid, [MarshalAs\(UnmanagedType.Interface\)] out object ppv\);

    public static bool Extract\(string path, string outPath\) {
        Guid IID = new Guid\(\\"bcc18b79-ba16-442f-80c4-8a59c30c463b\\"\);
        object shellItem;
        SHCreateItemFromParsingName\(path, IntPtr.Zero, ref IID, out shellItem\);
        var factory = \(IShellItemImageFactory2\)shellItem;
        IntPtr hbm;
        SIZE2 sz; sz.cx = 800; sz.cy = 600;
        int hr = factory.GetImage\(sz, SIIGBF2.ResizeToFit, out hbm\);
        if \(hr != 0\) return false;
        var bmp = Bitmap.FromHbitmap\(hbm\);
        var bmp2 = new Bitmap\(bmp.Width, bmp.Height, PixelFormat.Format32bppArgb\);
        using \(var g = Graphics.FromImage\(bmp2\)\) { g.DrawImageUnscaled\(bmp, 0, 0\); }
        bmp2.Save\(outPath, ImageFormat.Png\);
        return true;
    }
}
